import "./../App.css";
import "./../index.css"
import Input from "@/components/input";
import { Checkbox } from "@heroui/react";
import { Button } from "@/components/ui/button";
import { CardTitle, CardDescription } from "@/components/ui/card";
import { Avatar, AvatarImage, AvatarFallback } from "@/components/ui/avatar";
import { useState, useEffect } from "react";

import { motion, AnimatePresence, type Variants } from "motion/react";
const bgAlt = "/bg_alt.jpeg";
const nightlogo = "/nightlogo.png";
import { LoadingSpinner } from "@/components/spinner";
import { z } from "zod";
import { zodResolver } from "@hookform/resolvers/zod";
import { useForm } from "react-hook-form";
import { Form, FormControl, FormField, FormItem } from "@/components/ui/form";
import { toast } from "sonner";

const loginSchema = z.object({
  email: z.email("Invalid email address"),
  password: z.string().min(8, "Password must be at least 8 characters"),
});
const signUpSchema = z.object({
  username: z.string().min(4, "Username must be at least 4 characters"),
  email: z.email("Invalid email address"),
  password: z.string().min(8, "Password must be at least 8 characters"),
  avatar: z.instanceof(File).refine((file) => {
    if (!file) return false;
    const MAX_FILE_SIZE = 2 * 1024 * 1024; // 2mb
    const MAX_DIMENSION = 1024;
    if (file.size > MAX_FILE_SIZE) return false;
    const img = new Image();
    img.src = URL.createObjectURL(file);
    return new Promise((resolve) => {
      img.onload = () => {
        resolve(img.width <= MAX_DIMENSION && img.height <= MAX_DIMENSION);
      };
      img.onerror = () => resolve(false);
    });
  }, "Avatar image must be smaller than 2MB and not exceed 1024x1024 pixels"),
});

const formContainerVariants = {
  hidden: {
    transition: {
      staggerChildren: 0.08,
      staggerDirection: -1,
      delayChildren: 0.1,
    },
  },
  visible: {
    transition: {
      delayChildren: 0.1,
      staggerChildren: 0.08,
    },
  },
};
const sceneVariants = {
  hidden: {
    transition: {
      when: "afterChildren",
      staggerChildren: 0.08,
      staggerDirection: -1,
    },
  },
  visible: {
    transition: {
      delayChildren: 0.5,
      staggerChildren: 0.08,
    },
  },
};
const itemVariants: Variants = {
  hidden: {
    y: 20,
    opacity: 0,
    transition: { ease: [0.4, 0, 0.2, 1], duration: 0.3 },
  },
  visible: {
    y: 0,
    opacity: 1,
    transition: {
      ease: [0.4, 0, 0.2, 1],
      duration: 0.5,
      type: "spring",
      stiffness: 260,
      damping: 20,
    },
  },
};
function LoginFrame({service = "", visible = true, onLogin, onCancel, API_URL = "https://jwtauth-srv-api.night-x.com"}: { service: string, visible?: boolean; onLogin?: () => void, onCancel?: () => void, API_URL?: string }) {
  const [loading, setLoading] = useState(false);
  const [isSigningUp, setIsSigningUp] = useState(false);
  const [shouldAnimate, setShouldAnimate] = useState(false);
  const [userData, setUserData] = useState<string | null>(null);
  const [previewUsername, setPreviewUsername] = useState("");
  const [previewEmail, setPreviewEmail] = useState("");
  
  console.log(onCancel)
  const loginForm = useForm<z.infer<typeof loginSchema>>({
    resolver: zodResolver(loginSchema),
    defaultValues: {
      email: "",
      password: "",
    },
    mode: "onSubmit",
  });
  const signUpForm = useForm<z.infer<typeof signUpSchema>>({
    resolver: zodResolver(signUpSchema),
    defaultValues: {
      username: "",
      email: "",
      password: "",
      avatar: undefined,
    },
    mode: "onSubmit",
  });
  useEffect(() => {
    
    if (!visible) {
      setShouldAnimate(false)
    }
  }, [visible])
  
  useEffect(() => {
    const fetchUser = async () => {
      if (localStorage.getItem("access_token")) {
        const res = await fetch(`${API_URL}/get_user`, {
          method: "POST",
          credentials: "include",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            access_token: localStorage.getItem("access_token"),
          }),
        });

        if (!res.ok) {
          const timer = setTimeout(() => {
            setShouldAnimate(true);
          }, 800);
          return () => clearTimeout(timer);
        }

        const user_data = await res.json();
        setUserData(user_data);
        onLogin && onLogin();
      } else {
        const res = await fetch(`${API_URL}/refresh`, {
          method: "POST",
          credentials: "include",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({}),
        });
        if (!res.ok) {
          const timer = setTimeout(() => {
            setShouldAnimate(true);
          }, 800);
          return () => clearTimeout(timer);
        }
        const refresh_data = await res.json();
        localStorage.setItem("access_token", refresh_data.access_token);
        onLogin && onLogin();
      }
    };

    fetchUser();
  }, [userData]);

  const toggleForm = () => {
    setIsSigningUp(!isSigningUp);
  };

  const handleLogin = async (values: z.infer<typeof loginSchema>) => {
    try {
      setLoading(true);
      const res = await fetch(`${API_URL}/login`, {
        method: "POST",
        credentials: "include",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(values),
      });
      const data = await res.json();
      if (!res.ok) {
        toast.error(data.error || "Login failed");
        setLoading(false);
        return;
      }

      localStorage.setItem("access_token", data.access_token);
      toast.success("Welcome back!", {
        description: "Please consent to share your basic profile info with " + service,
      });

      setLoading(false);
      setShouldAnimate(false);
      setTimeout(function () {
        onLogin && onLogin();
      }, 1000);
    } catch (err) {
      toast.error("Network error: " + err);
      setLoading(false);
    }
  };

  const handleSignUp = async (values: z.infer<typeof signUpSchema>) => {
    setLoading(true);

    try {
      const avatarFile = values.avatar as File;

      if (!avatarFile) {
        toast.error("Avatar is required; please upload one.");
        setLoading(false);
        return;
      }

      const MAX_FILE_SIZE = 2 * 1024 * 1024;
      const MAX_DIMENSION = 1024;

      if (avatarFile.size > MAX_FILE_SIZE) {
        toast.error("Avatar image must be smaller than 2MB.");
        setLoading(false);
        return;
      }

      const img = new Image();
      const objectUrl = URL.createObjectURL(avatarFile);

      await new Promise((resolve, reject) => {
        img.onload = () => {
          if (img.width > MAX_DIMENSION || img.height > MAX_DIMENSION) {
            toast.error(
              "Avatar image resolution must not exceed 1024x1024 pixels."
            );
            URL.revokeObjectURL(objectUrl);
            reject(new Error("Invalid image dimensions"));
            return;
          }
          resolve(null);
        };

        img.onerror = () => {
          toast.error("Invalid image file.");
          URL.revokeObjectURL(objectUrl);
          reject(new Error("Invalid image file"));
        };

        img.src = objectUrl;
      });

      URL.revokeObjectURL(objectUrl);
      const avatarBuffer = await avatarFile.arrayBuffer();

      const res = await fetch(`${API_URL}/register`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          username: values.username,
          password: values.password,
          email: values.email,
          avatar: Array.from(new Uint8Array(avatarBuffer)),
        }),
      });

      const data = await res.json();
      if (!res.ok) {
        toast.error(data.error || "Registration failed");
        setLoading(false);
        return;
      }

      toast.success("Account created successfully!", {
        description:
          "You can login with your new account if you want to redeem a Night+ subscription.",
      });
      setLoading(false);
      setIsSigningUp(false);
    } catch (err) {
      toast.error("Network error: " + err);
      setLoading(false);
    }
  };
  

  return (
    <div className="font flex flex-col items-center justify-center min-h-screen text-foreground">
      <motion.div
        initial={{ opacity: 0, scale: 0.95 }}
        animate={
          shouldAnimate ? { opacity: 1, scale: 1 } : { opacity: 0, scale: 0.95 }
        }
        variants={sceneVariants}
        transition={{ duration: 0.4, ease: [0.4, 0, 0.2, 1] }}
        className="relative z-0 h-[calc(67vh+64px)] p-[24px] w-[60vw] rounded-[54px] flex flex-row bg-card border-x-[1.5px] border-t border-b border-border overflow-hidden"
      >
        <motion.div
          initial={{
            scale: 1,
            rotateY: 0,
            perspective: 800,
            transformStyle: "preserve-3d",
            filter: "blur(25px) brightness(1)",
            x: 15,
          }}
          animate={
            shouldAnimate
              ? {
                  scale: 1.02,
                  rotateY: 8,
                  perspective: 800,
                  transformStyle: "preserve-3d",
                  filter: "blur(0px) brightness(0.95)",
                  x: 0,
                }
              : {
                  scale: 0.9,
                  rotateY: 0,
                  perspective: 800,
                  transformStyle: "preserve-3d",
                  filter: "blur(15px) brightness(1.5)",
                  x: 15,
                }
          }
          transition={{
            duration: 0.3,
            delay: 0.1,
            ease: [0.4, 0, 0.2, 1],
            rotateY: { duration: 0.4 },
            scale: { duration: 0.4 },
            x: { duration: 0.5 },
          }}
          style={{
            transformOrigin: "right center",
          }}
          className="relative flex-1 overflow-hidden w-full rounded-[30px] h-full"
        >
          <motion.img
            src={bgAlt}
            alt="Visual background"
            initial={{ scale: 1.1, x: 15 }}
            animate={
              shouldAnimate ? { scale: 1.15, x: 0 } : { scale: 1.1, x: 15 }
            }
            transition={{
              duration: 0.4,
              delay: 0.15,
              ease: [0.4, 0, 0.2, 1],
            }}
            className="w-full rounded-[30px] h-full object-cover"
            style={{ transformOrigin: "center center" }}
          />
        </motion.div>

        <div className="flex-1 flex flex-col items-center justify-center z-10 mt-[-20px] p-0">
          <motion.div
            initial={{ opacity: 0, x: -30 }}
            animate={
              shouldAnimate ? { opacity: 1, x: 0 } : { opacity: 0, x: -30 }
            }
            transition={{
              duration: 0.4,
              delay: 0.3,
              ease: [0.4, 0, 0.2, 1],
            }}
            className="logo_parent flex flex-row items-center justify-center space-x-2 pt-[30px]"
          >
            <motion.div
              initial={{ scale: 0.3, opacity: 0 }}
              animate={
                shouldAnimate
                  ? { scale: 1, opacity: 1 }
                  : { scale: 0.3, opacity: 0 }
              }
              transition={{
                duration: 0.8,
                delay: 0.55,
                type: "spring",
                bounce: 0.6,
                ease: [0.4, 0, 0.2, 1],
              }}
            >
              <Avatar className="w-7 h-7">
                <AvatarImage src={nightlogo} alt="Logo" />
                <AvatarFallback>NG</AvatarFallback>
              </Avatar>
            </motion.div>

            <motion.p
              initial={{ opacity: 0, x: -30 }}
              animate={
                shouldAnimate ? { opacity: 1, x: 0 } : { opacity: 0, x: -30 }
              }
              transition={{
                duration: 0.6,
                delay: 0.3,
                ease: [0.4, 0, 0.2, 1],
              }}
              className="text-bold text-foreground"
            >
              Night Network
            </motion.p>
          </motion.div>

          <AnimatePresence mode="wait">
            <motion.div
              key={isSigningUp ? "signup" : "signin"}
              variants={formContainerVariants}
              initial="hidden"
              animate={shouldAnimate ? "visible" : "hidden"}
              exit="hidden"
              transition={{ delay: 0.6 }}
              className="w-[70%] text-center"
            >
              {!isSigningUp && (
                <motion.div
                  variants={itemVariants}
                  className="translate-y-[15px] mb-4"
                >
                  <CardTitle className="text-3xl scale-[0.9]">
                    {isSigningUp ? "Create Account" : "Welcome back!"}
                  </CardTitle>
                  <CardDescription className="text-sm mt-1">
                    {isSigningUp
                      ? "Get started with Night!"
                      : `Continue to ${service} with Night`}
                  </CardDescription>
                </motion.div>
              )}
              {isSigningUp && (
                <motion.div
                  variants={itemVariants}
                  className="translate-y-[15px] mb-2"
                >
                  <CardTitle className="text-3xl scale-[0.9]">
                    {isSigningUp ? "Create Account" : "Welcome back!"}
                  </CardTitle>
                  <CardDescription className="text-sm mt-1">
                    {isSigningUp
                      ? "Get started with Night!"
                      : `Continue to ${service} with Night`}
                  </CardDescription>
                </motion.div>
              )}

              {isSigningUp ? (
                <Form {...signUpForm}>
                  <form
                    onSubmit={signUpForm.handleSubmit(
                      handleSignUp,
                      (errors) => {
                        const errorMessages = Object.entries(errors).map(
                          ([field, error]) => ({
                            field:
                              field.charAt(0).toUpperCase() + field.slice(1),
                            message: (error as { message?: string })?.message,
                          })
                        );
                        errorMessages.forEach((err) => {
                          toast.error(err.field, {
                            description: err.message,
                          });
                        });
                      }
                    )}
                    className="flex flex-col space-y-4 transform scale-[0.85] -translate-y-2"
                  >
                    <motion.div variants={itemVariants}>
                      <FormField
                        control={signUpForm.control}
                        name="username"
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <Input
                                label="Username"
                                placeholder="Your username..."
                                {...field}
                                onChange={(e) => {
                                  field.onChange(e);
                                  setPreviewUsername(e.target.value);
                                }}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <FormField
                        control={signUpForm.control}
                        name="email"
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <Input
                                label="Email address"
                                type="email"
                                placeholder="Your email..."
                                {...field}
                                onChange={(e) => {
                                  field.onChange(e);
                                  setPreviewEmail(e.target.value);
                                }}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <FormField
                        control={signUpForm.control}
                        name="password"
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <Input
                                label="Password"
                                type="password"
                                placeholder="Your password..."
                                {...field}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <FormField
                        control={signUpForm.control}
                        name="avatar"
                        render={({ field: { onChange, ...field } }) => (
                          <FormItem>
                            <FormControl>
                              <Input
                                label="Avatar"
                                type="file"
                                previewUsername={previewUsername}
                                previewEmail={previewEmail}
                                onChange={(e) => {
                                  const file = e.target.files?.[0];
                                  if (file && file.type.startsWith("image/")) {
                                    onChange(file);
                                  }
                                }}
                                {...field}
                                value={field.value ? "" : undefined}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <Button
                        className="w-full rounded-full hover:cursor-pointer p-[23px]"
                        type="submit"
                        disabled={loading}
                      >
                        {loading ? (
                          <>
                            <LoadingSpinner size={18} className="" />
                            Loading...
                          </>
                        ) : (
                          "Create Account"
                        )}
                      </Button>
                    </motion.div>
                  </form>
                </Form>
              ) : (
                <Form {...loginForm}>
                  <form
                    onSubmit={loginForm.handleSubmit(handleLogin, (errors) => {
                      const errorMessages = Object.entries(errors).map(
                        ([field, error]) => ({
                          field: field.charAt(0).toUpperCase() + field.slice(1),
                          message: error?.message,
                        })
                      );
                      errorMessages.forEach((err) => {
                        toast.error(err.field, {
                          description: err.message,
                        });
                      });
                    })}
                    className="flex flex-col space-y-3 transform scale-[0.85] -translate-y-2"
                  >
                    <motion.div variants={itemVariants}>
                      <FormField
                        control={loginForm.control}
                        name="email"
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <Input
                                label="Email address"
                                type="email"
                                placeholder="Your email..."
                                {...field}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <FormField
                        control={loginForm.control}
                        name="password"
                        render={({ field }) => (
                          <FormItem>
                            <FormControl>
                              <Input
                                label="Password"
                                type="password"
                                placeholder="Your password..."
                                {...field}
                              />
                            </FormControl>
                          </FormItem>
                        )}
                      />
                    </motion.div>

                    <motion.div
                      variants={itemVariants}
                      className="flex flex-row translate-y-[-13px]"
                    >
                      <Checkbox
                        defaultSelected
                        radius="full"
                        className="pl-0 pt-0 whitespace-nowrap"
                        style={{ transform: "scale(0.65) translate(-20px)" }}
                      >
                        Remember me
                      </Checkbox>
                      <Button
                        className="ml-auto pl-0 pt-0 text-muted-foreground"
                        style={{ transform: "scale(0.8) translateX(15px)" }}
                        variant="link"
                      >
                        Forgot password?
                      </Button>
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <Button
                        className="w-full rounded-full hover:cursor-pointer p-[23px]"
                        type="submit"
                        disabled={loading}
                      >
                        {loading ? (
                          <>
                            <LoadingSpinner size={18} className="" />
                            Loading...
                          </>
                        ) : (
                          "Sign In"
                        )}
                      </Button>
                    </motion.div>

                    <motion.div variants={itemVariants}>
                      <Button
                        className="w-full rounded-full hover:cursor-pointer p-[23px]"
                        variant="outline"
                      >
                        Sign in with...
                      </Button>
                    </motion.div>
                  </form>
                </Form>
              )}

              <motion.div
                variants={itemVariants}
                className="mt-2 transform scale-[0.85]"
              >
                <CardDescription className="text-muted-foreground text-xs mt-[-25px]">
                  {isSigningUp
                    ? "Already have an account?"
                    : "Don't have an account?"}{" "}
                  <Button
                    variant="link"
                    className="pl-1 text-xs pb-0"
                    onClick={toggleForm}
                    type="button"
                  >
                    {isSigningUp ? "Sign in" : "Sign up"}
                  </Button>
                </CardDescription>
              </motion.div>
            </motion.div>
          </AnimatePresence>
        </div>
      </motion.div>
    </div>
  );
}

export default LoginFrame;
