import React from "react";
import { createRoot, type Root } from "react-dom/client";
import LoginFrame from "./loginFrame";
import { SignInWithNight } from "./signInWithNight";

type Props = {
  service: string;
  onAuth?: (token: string) => void;
  onCancel?: () => void;
};

const NightLoginFrame = {
  render: (element: HTMLElement, props: Props) => {
   
    const root = createRoot(element);
    root.render(React.createElement(LoginFrame as any, props));
    
    (element as any).__night_root = root as Root;
  },
  unmount: (element: HTMLElement) => {
    const root = (element as any).__night_root as Root | undefined;
    if (root && typeof root.unmount === "function") {
      root.unmount();
    } else {
      element.innerHTML = "";
    }
  },
};

export default NightLoginFrame;


export { SignInWithNight };
